import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_pkgs(data):
    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-2]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result.setdefault(name, {})[pkg['id']] = pkg['resolvedVersion']
    return result

b, a = get_pkgs(baseline), get_pkgs(after)
changes = []
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for pkg in sorted(set(list(b.get(proj, {}).keys()) + list(a.get(proj, {}).keys()))):
        bv = b.get(proj, {}).get(pkg, 'MISSING')
        av = a.get(proj, {}).get(pkg, 'MISSING')
        if bv != av:
            changes.append((proj, pkg, bv, av))
if changes:
    for c in changes: print(f'CHANGED: {c[0]} {c[1]} {c[2]} -> {c[3]}')
else:
    print('All packages resolve identically to baseline.')
"

